// // This module implements a 2-input OR gate configuration using positive logic for inputs A1 and A2 and inverted logic for inputs B1 and B2. The output X will be HIGH when either A1 or A2 is HIGH, and either B1 or B2 is LOW.
module top_module(
    X   ,
    A1_N,
    A2_N,
    B1  ,
    B2
);output X   ;
    input  A1_N;
    input  A2_N;
    input  B1  ;
    input  B2  ;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Use a conditional assignment instead of the missing module
    assign X = (~A1_N & ~A2_N & B1 & B2);

endmodule
